using System.Collections.Generic;
using System.Threading;
using Cysharp.Threading.Tasks;
using UnityEngine;

namespace DevWorkbench
{
    /// <summary>
    /// Base class for a <see cref="ScriptableObject"/> that stores the author-time
    /// configuration of a Manager. A concrete <c>XxxManagerConfig</c> is typically
    /// generated by the DevWorkbench Creator and persists a list of
    /// <see cref="BaseManagerData"/> records keyed by <c>Key</c>.
    /// </summary>
    public abstract class BaseManagerConfig : ScriptableObject
    {
        /// <summary>
        /// Produce the key/value lookup consumed by the framework at runtime.
        /// Implementations normally return the content of the serialised list.
        /// </summary>
        protected abstract Dictionary<string, BaseManagerData> GetManagerDataDict();

        /// <summary>
        /// Cross-assembly accessor for <see cref="GetManagerDataDict"/>. Called by the
        /// architecture layer and by Manager code outside this assembly; exposed as
        /// <c>public</c> because <c>protected</c> is not reachable across assemblies.
        /// </summary>
        public Dictionary<string, BaseManagerData> ExportManagerDataDict() => GetManagerDataDict();
    }

    /// <summary>
    /// Base class for the per-entry record inside a <see cref="BaseManagerConfig"/>.
    /// Concrete subclasses declare the serialisable fields that describe a single
    /// Manager entry (e.g. its key and payload).
    /// </summary>
    public abstract class BaseManagerData
    {
    }

    /// <summary>
    /// Base class for every Manager registered into the Dev Workbench lifetime scope.
    /// A Manager typically owns a <see cref="BaseManagerConfig"/> and populates its
    /// internal state in <see cref="SetManagerDataDict"/> before the game starts.
    /// The Addressable address of that config is baked into the generated partial
    /// (by DevWorkbench's Creator) and is no longer part of the base contract.
    /// </summary>
    public abstract class BaseManager
    {
        /// <summary>
        /// Loads the Manager's configuration (via <see cref="FrameworkLoader"/>)
        /// and populates the in-memory data dictionary. Called once during
        /// bootstrap, before any <see cref="IAsyncInitManager.InitAsync"/>.
        /// </summary>
        protected abstract UniTask SetManagerDataDict();

        internal async UniTask InternalSetManagerDataDict() => await SetManagerDataDict();
    }

    /// <summary>
    /// Entry point for the user-authored game boot code. A single
    /// MonoBehaviour implementing <see cref="IGameBoot"/> is expected on the
    /// <c>Managers</c> GameObject; the framework resolves it after every
    /// Manager has completed initialisation and invokes
    /// <see cref="OnGameStart"/>.
    /// </summary>
    public interface IGameBoot
    {
        /// <summary>
        /// Called by the framework exactly once, after all Managers have finished
        /// their data loading and async initialisation.
        /// </summary>
        void OnGameStart();
    }

    /// <summary>
    /// Optional contract for Managers that need an additional asynchronous
    /// initialisation step after <see cref="BaseManager.SetManagerDataDict"/>.
    /// The framework calls <see cref="InitAsync"/> once, in registration order,
    /// before <see cref="IGameBoot.OnGameStart"/>.
    /// </summary>
    public interface IAsyncInitManager
    {
        /// <summary>
        /// Perform Manager-specific async initialisation. Implementations should
        /// honour <paramref name="token"/> for cancellation.
        /// </summary>
        UniTask InitAsync(CancellationToken token);
    }

#if UNITY_EDITOR
    /// <summary>
    /// Editor-only contract used by DevWorkbench to re-populate a
    /// <see cref="BaseManagerConfig"/> asset from external sources (e.g.
    /// scanning folders). Concrete refreshers live alongside their Manager in
    /// <c>Assets/Game/Manager/</c> and are discovered by reflection.
    /// </summary>
    public interface IManagerRefresher
    {
        /// <summary>
        /// Rebuild <paramref name="config"/> in place and mark it dirty. The
        /// workbench saves the asset afterwards.
        /// </summary>
        void Refresh(BaseManagerConfig config);
    }
#endif
}
